bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = true;
  bool EverChanged = false;

  while (Changed) {
    Changed = false;
    for (BasicBlock *BB : ReversePostOrderTraversal<Function *>(&Foo)) {
      for (auto It = BB->begin(), End = BB->end(); It != End;) {
        Instruction &I = *It++;
        auto *BinOp = dyn_cast<BinaryOperator>(&I);
        if (!BinOp)
          continue;

        auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
        auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
        if (!LHS || !RHS)
          continue;

        const APInt &L = LHS->getValue();
        const APInt &R = RHS->getValue();
        std::optional<APInt> Result;

        switch (BinOp->getOpcode()) {
        case Instruction::Add:  Result = L + R; break;
        case Instruction::Sub:  Result = L - R; break;
        case Instruction::Mul:  Result = L * R; break;
        case Instruction::SDiv:
          if (!R.isZero()) Result = L.sdiv(R);
          break;
        case Instruction::UDiv:
          if (!R.isZero()) Result = L.udiv(R);
          break;
        case Instruction::Shl:  Result = L.shl(R); break;
        case Instruction::LShr: Result = L.lshr(R); break;
        case Instruction::AShr: Result = L.ashr(R); break;
        case Instruction::And:  Result = L & R; break;
        case Instruction::Or:   Result = L | R; break;
        case Instruction::Xor:  Result = L ^ R; break;
        default: break;
        }

        if (!Result)
          continue;

        auto *NewConst = ConstantInt::get(BinOp->getType(), *Result);
        BinOp->replaceAllUsesWith(NewConst);
        BinOp->eraseFromParent();
        Changed = true;
        EverChanged = true;
      }
    }
  }

  return EverChanged;
}

